const FOODS = Object.assign({}, FOODS_BASE, FOODS_EXTRA);

/* ── MEDIDAS CASERAS aproximadas ────────────────────────────
   Para no tener que pesar a diario: cantidades típicas por pieza/medida.
   Se aplican a los alimentos que aún no tengan "unit" propia. */
