    if(!list.length){ el.innerHTML=''; return; }
    const avg = list.reduce((a,e)=>a+e.rating,0)/list.length;
    const sb = bySlot(list).filter(s=>s.n).sort((a,b)=>b.avg-a.avg);
    const best = sb[0];
